-- Targeted migration: fill Cisco CCNA 200-301-P1..P6 pools to 100.
-- 240 grounded questions across 5 under-served domains per blueprint:
--   Network Fundamentals, Network Access, IP Services, Security Fundamentals, Automation and Programmability
-- Skips IP Connectivity (already over-represented in all 6 pools).
-- Does NOT touch published/deletedAt or any other field.
-- Idempotent via WHERE NOT EXISTS on (examId, stem).

CREATE EXTENSION IF NOT EXISTS pgcrypto;

-- 200-301-P1: 40 new questions
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A network engineer is troubleshooting a connectivity issue and needs to identify which OSI layer is responsible for routing packets based on the destination IP address. Which OSI layer handles this function?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Layer 1 – Physical"},{"id":"b","text":"Layer 2 – Data Link"},{"id":"c","text":"Layer 3 – Network"},{"id":"d","text":"Layer 4 – Transport"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material states that routers operate at Layer 3 and 'route packets based on dst IP.' Layer 3 (Network) is responsible for logical addressing and path determination using IP addresses. Layer 2 (Data Link) uses MAC addresses for local forwarding, Layer 1 (Physical) handles raw bit transmission, and Layer 4 (Transport) manages end-to-end communication and segmentation — none of which involve IP-based routing decisions.$patch$, $patch$Network Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/training-events/training-certifications/certifications/associate/ccna.html","label":"Cisco CCNA 200-301 Official Cert Guide – OSI Model"},{"url":"https://learningnetwork.cisco.com/s/article/osi-model-reference-chart","label":"Cisco Learning Network – OSI Reference Model"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A network engineer is troubleshooting a connectivity issue and needs to identify which OSI layer is responsible for routing packets based on the destination IP address. Which OSI layer handles this function?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which IPv4 address range is defined by RFC 1918 as a private address space with a /12 prefix length?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"10.0.0.0 – 10.255.255.255"},{"id":"b","text":"172.16.0.0 – 172.31.255.255"},{"id":"c","text":"192.168.0.0 – 192.168.255.255"},{"id":"d","text":"169.254.0.0 – 169.254.255.255"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material lists the three RFC 1918 private ranges as '10/8, 172.16-31/12, 192.168/16.' The 172.16.0.0/12 block spans 172.16.0.0 through 172.31.255.255. The 10.0.0.0/8 block is a /8, not /12. The 192.168.0.0/16 block is a /16. The 169.254.0.0/16 range is APIPA (Automatic Private IP Addressing), not an RFC 1918 private range.$patch$, $patch$Network Fundamentals$patch$,
         3, $json$[{"url":"https://datatracker.ietf.org/doc/html/rfc1918","label":"RFC 1918 – Address Allocation for Private Internets"},{"url":"https://www.cisco.com/c/en/us/support/docs/ip/routing-information-protocol-rip/13788-3.html","label":"Cisco – IP Addressing and Subnetting for New Users"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which IPv4 address range is defined by RFC 1918 as a private address space with a /12 prefix length?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A switch receives a frame destined for a MAC address that does not exist in its MAC address table. What action does the switch take?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Drops the frame silently"},{"id":"b","text":"Sends an ARP request to learn the destination MAC address"},{"id":"c","text":"Floods the frame out all ports except the port on which it was received"},{"id":"d","text":"Forwards the frame only to the default gateway port"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material states that switches perform 'Flooding (unknown unicast/multicast/broadcast)' when the destination MAC is not found in the CAM table. This means the switch copies the frame and sends it out every port except the ingress port, allowing the intended destination to receive and respond. Dropping the frame would cause communication failure. Switches do not issue ARP requests — that is a host function. Switches have no concept of forwarding to a default gateway.$patch$, $patch$Network Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/support/docs/lan-switching/ethernet/12006-chapter2.html","label":"Cisco – How Switches Forward Frames"},{"url":"https://learningnetwork.cisco.com/s/article/switching-fundamentals","label":"Cisco CCNA 200-301 – LAN Switching Concepts"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A switch receives a frame destined for a MAC address that does not exist in its MAC address table. What action does the switch take?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An administrator needs to connect two routers back-to-back over a point-to-point serial link and wants to conserve IP address space as much as possible while still using a standard routable subnet. Which subnet mask should be used?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"/24 — provides 254 usable host addresses"},{"id":"b","text":"/30 — provides 2 usable host addresses"},{"id":"c","text":"/28 — provides 14 usable host addresses"},{"id":"d","text":"/16 — provides 65,534 usable host addresses"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material states that '/30 = 4 addrs (2 usable, point-to-point).' A /30 subnet yields exactly two usable host addresses, which is the minimum for a traditional point-to-point link between two routers. This conserves IP address space compared to /28 (14 usable), /24 (254 usable), or /16 (65,534 usable). Note: RFC 3021 /31 subnets also exist for P2P links without broadcast, but /30 is the traditional and widely tested choice at the CCNA level.$patch$, $patch$Network Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/support/docs/ip/routing-information-protocol-rip/13788-3.html","label":"Cisco – IP Addressing and Subnetting for New Users"},{"url":"https://datatracker.ietf.org/doc/html/rfc3021","label":"RFC 3021 – Using 31-Bit Prefixes on IPv4 Point-to-Point Links"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An administrator needs to connect two routers back-to-back over a point-to-point serial link and wants to conserve IP address space as much as possible while still using a standard routable subnet. Which subnet mask should be used?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which IPv6 address type is automatically configured on every IPv6-enabled interface and is only valid for communication within the local network segment?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Global Unicast address (2000::/3)"},{"id":"b","text":"Unique Local address (FC00::/7)"},{"id":"c","text":"Link-Local address (FE80::/10)"},{"id":"d","text":"Multicast address (FF00::/8)"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material identifies the Link-Local prefix as 'FE80::/10' and implies it is scoped to the local link. Link-Local addresses are automatically derived (often via EUI-64) on every IPv6-enabled interface and cannot be routed beyond the local segment. Global Unicast (2000::/3) addresses are globally routable and must be assigned. Unique Local (FC00::/7) addresses are similar to RFC 1918 private addresses but are routable within a site. Multicast (FF00::/8) addresses are used for one-to-many communication, not unicast link-local communication.$patch$, $patch$Network Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/ipv6_basic/configuration/xe-16/ip6b-xe-16-book/ip6-add-basic-conn.html","label":"Cisco – IPv6 Addressing Overview"},{"url":"https://datatracker.ietf.org/doc/html/rfc4291","label":"RFC 4291 – IP Version 6 Addressing Architecture"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which IPv6 address type is automatically configured on every IPv6-enabled interface and is only valid for communication within the local network segment?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A technician is configuring a Cisco switch via the CLI and needs to set a hostname. The prompt currently displays 'Switch>'. What must the technician do before entering the hostname command?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Type 'enable' to enter Privileged EXEC mode, then type 'configure terminal' to enter Global Configuration mode"},{"id":"b","text":"Type 'configure terminal' directly from User EXEC mode"},{"id":"c","text":"Type 'hostname' directly — the command is available in User EXEC mode"},{"id":"d","text":"Type 'enable secret' to unlock Global Configuration mode"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$The source material lists Cisco IOS modes as 'User EXEC (>), Privileged EXEC (#), Global config, Interface config modes.' The 'Switch>' prompt indicates User EXEC mode, which provides very limited commands. The technician must first type 'enable' to reach Privileged EXEC mode (Switch#), then 'configure terminal' to enter Global Configuration mode (Switch(config)#) where the 'hostname' command is available. Typing 'configure terminal' directly from User EXEC mode is not permitted. The 'enable secret' command sets an encrypted password and does not transition into Global Configuration mode by itself.$patch$, $patch$Network Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/fundamentals/command/cf_command_ref.html","label":"Cisco IOS Configuration Fundamentals Command Reference"},{"url":"https://learningnetwork.cisco.com/s/article/ios-cli-modes","label":"Cisco Learning Network – IOS CLI Modes"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A technician is configuring a Cisco switch via the CLI and needs to set a hostname. The prompt currently displays 'Switch>'. What must the technician do before entering the hostname command?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which copper Ethernet cabling standard supports 10 Gbps at a maximum distance of 100 meters?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Cat5e"},{"id":"b","text":"Cat6"},{"id":"c","text":"Cat6a"},{"id":"d","text":"Single-mode fiber"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material specifies 'Cat6a (10 Gbps, 100m)' as the standard that achieves 10 Gbps at the full 100-meter distance. Cat5e supports only up to 1 Gbps. Cat6 can support 10 Gbps but only up to 55 meters (not the full 100m), making Cat6a the correct choice for 10 Gbps at 100m. Single-mode fiber is an optical medium, not copper, and is used for long-distance runs — it is outside the copper cabling category.$patch$, $patch$Network Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/products/collateral/switches/catalyst-9000/nb-06-cat9k-port-ntwk-design-cbl-wp-cte-en.html","label":"Cisco – Cabling Specifications and Constraints"},{"url":"https://www.tiaonline.org/standards/tia-568/","label":"TIA-568-C.2 Balanced Twisted-Pair Telecommunications Cabling and Components Standard"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which copper Ethernet cabling standard supports 10 Gbps at a maximum distance of 100 meters?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In IPv6, which protocol replaces the functionality of both ARP (Address Resolution Protocol) and ICMP Redirect messages used in IPv4?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"DHCPv6"},{"id":"b","text":"OSPFv3"},{"id":"c","text":"Neighbor Discovery Protocol (NDP)"},{"id":"d","text":"ICMPv4"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material explicitly states 'NDP (replaces ARP+ICMP redirect): NS/NA, RS/RA.' Neighbor Discovery Protocol (NDP) uses ICMPv6 message types — Neighbor Solicitation (NS), Neighbor Advertisement (NA), Router Solicitation (RS), and Router Advertisement (RA) — to perform address resolution, duplicate address detection, and router discovery. DHCPv6 is used for stateful address assignment, not address resolution. OSPFv3 is a routing protocol. ICMPv4 is the IPv4 version of ICMP and is not used in IPv6 environments.$patch$, $patch$Network Fundamentals$patch$,
         3, $json$[{"url":"https://datatracker.ietf.org/doc/html/rfc4861","label":"RFC 4861 – Neighbor Discovery for IP Version 6 (IPv6)"},{"url":"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/ipv6_basic/configuration/xe-16/ip6b-xe-16-book/ip6-neighb-disc.html","label":"Cisco – IPv6 Neighbor Discovery"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$In IPv6, which protocol replaces the functionality of both ARP (Address Resolution Protocol) and ICMP Redirect messages used in IPv4?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A network administrator wants to carry traffic for VLANs 10, 20, and 30 across a single link between two Cisco switches. Which port mode must be configured on both ends of that link to allow tagged traffic for multiple VLANs?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Access mode"},{"id":"b","text":"Trunk mode"},{"id":"c","text":"Dynamic auto mode"},{"id":"d","text":"Voice VLAN mode"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Trunk ports carry multiple VLANs over a single link using 802.1Q tagging, as stated in the source material: 'Trunk ports (multiple VLANs, 802.1Q tagging).' Access ports (option A) carry only a single, untagged VLAN. Dynamic auto (option C) is a DTP negotiation mode that may or may not form a trunk depending on the other side, and is not a definitive configuration. Voice VLAN mode (option D) is not an independent port mode—it is a supplemental configuration applied alongside an access mode port.$patch$, $patch$Network Access$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/switches/lan/catalyst9300/software/release/17-9/configuration_guide/vlan/b_179_vlan_9300_cg/configuring_vlans.html","label":"Cisco - VLAN Configuration Guide"},{"url":"https://www.ciscopress.com/store/ccna-200-301-official-cert-guide-library-9780138097790","label":"Cisco CCNA 200-301 Official Cert Guide"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A network administrator wants to carry traffic for VLANs 10, 20, and 30 across a single link between two Cisco switches. Which port mode must be configured on both ends of that link to allow tagged traffic for multiple VLANs?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which field within the 802.1Q frame tag carries the VLAN identifier, and how many bits are allocated to it?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"TPID field; 16 bits"},{"id":"b","text":"PCP field; 3 bits"},{"id":"c","text":"VID field; 12 bits"},{"id":"d","text":"DEI field; 1 bit"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material states: '802.1Q tag is 4 bytes (TPID 0x8100 + TCI with PCP/DEI/VID 12-bit).' The VID (VLAN Identifier) is the 12-bit field within the Tag Control Information (TCI) portion of the 802.1Q header that identifies which VLAN a frame belongs to, allowing up to 4094 usable VLANs. TPID (option A) is the 16-bit Tag Protocol Identifier set to 0x8100 that signals an 802.1Q-tagged frame. PCP (option B) is the 3-bit Priority Code Point used for QoS marking. DEI (option D) is a single bit used to indicate frames eligible for dropping under congestion.$patch$, $patch$Network Access$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/switches/lan/catalyst9300/software/release/17-9/configuration_guide/vlan/b_179_vlan_9300_cg/configuring_vlans.html","label":"IEEE 802.1Q Standard Overview - Cisco"},{"url":"https://en.wikipedia.org/wiki/IEEE_802.1Q","label":"IEEE 802.1Q - Wikipedia (structure reference)"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which field within the 802.1Q frame tag carries the VLAN identifier, and how many bits are allocated to it?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Cisco switch port is configured with 'switchport mode dynamic auto'. The switch on the other end is also configured with 'switchport mode dynamic auto'. What will be the resulting port state?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The link will form a trunk because both sides are using DTP."},{"id":"b","text":"The link will remain an access port because neither side actively initiates trunking."},{"id":"c","text":"The link will be placed in an error-disabled state."},{"id":"d","text":"The link will use 802.1Q by default and forward all VLANs."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source notes that DTP modes include 'auto' and 'desirable.' Dynamic auto means the port will respond to DTP negotiation but will NOT actively initiate it. When both sides are set to auto, neither side initiates trunking, so the result is an access port. For a trunk to form via DTP, at least one side must be set to 'desirable' (actively initiates). Error-disabled state (option C) is caused by security violations or BPDU Guard events, not DTP mismatches. Option D is incorrect because no trunk is established.$patch$, $patch$Network Access$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/tech/lan-switching/dynamic-trunking-protocol-dtp/index.html","label":"Cisco - Configuring Dynamic Trunking Protocol"},{"url":"https://www.cisco.com/c/en/us/support/docs/lan-switching/8021q/17056-741-4.html","label":"Cisco Catalyst Switch DTP Configuration"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Cisco switch port is configured with 'switchport mode dynamic auto'. The switch on the other end is also configured with 'switchport mode dynamic auto'. What will be the resulting port state?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An administrator needs to implement inter-VLAN routing on a Cisco router connected to a single trunk link from a switch. The router has one physical interface. Which configuration approach is required?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Configure a Switch Virtual Interface (SVI) on the router for each VLAN."},{"id":"b","text":"Configure subinterfaces on the router's physical interface with 'encapsulation dot1q' per VLAN."},{"id":"c","text":"Configure EtherChannel between the router and switch, assigning each channel to a VLAN."},{"id":"d","text":"Enable VTP server mode on the router to propagate VLAN routes."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material explicitly describes this design: 'Router-on-a-stick: subinterfaces with encapsulation dot1q.' A single physical interface is divided into logical subinterfaces (e.g., Gi0/0.10, Gi0/0.20), each configured with 'encapsulation dot1q <vlan-id>' to handle traffic for a specific VLAN over the shared trunk link. SVIs (option A) exist on Layer 3 switches, not on traditional routers. EtherChannel (option C) aggregates bandwidth between links but does not perform inter-VLAN routing by itself. VTP (option D) propagates VLAN database information, not routing.$patch$, $patch$Network Access$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/support/docs/lan-switching/inter-vlan-routing/41860-howto-L3-intervlanrouting.html","label":"Cisco - Router on a Stick Inter-VLAN Routing"},{"url":"https://www.cisco.com/c/en/us/td/docs/switches/lan/catalyst9300/software/release/17-9/configuration_guide/rtng/b_179_rtng_9300_cg/configuring_layer_3_interfaces.html","label":"Cisco CCNA 200-301 - Inter-VLAN Routing"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An administrator needs to implement inter-VLAN routing on a Cisco router connected to a single trunk link from a switch. The router has one physical interface. Which configuration approach is required?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A network engineer is deploying Rapid PVST+ on a Cisco campus network. Which port states are valid under Rapid PVST+ (802.1w)?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Blocking, Listening, Learning, Forwarding, Disabled"},{"id":"b","text":"Blocking, Learning, Forwarding"},{"id":"c","text":"Discarding, Learning, Forwarding"},{"id":"d","text":"Discarding, Listening, Forwarding"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material clearly differentiates: 'Port states (STP): blocking, listening, learning, forwarding, disabled. RSTP: discarding, learning, forwarding.' Rapid PVST+ is Cisco's per-VLAN implementation of 802.1w (RSTP), which consolidates blocking, listening, and disabled into a single 'discarding' state, resulting in only three states: discarding, learning, and forwarding. Option A lists the five classic 802.1D STP states. Option B removes the discarding label incorrectly. Option D incorrectly includes 'listening,' which belongs to 802.1D only.$patch$, $patch$Network Access$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/support/docs/lan-switching/spanning-tree-protocol/24062-146.html","label":"Cisco - Understanding Rapid Spanning Tree Protocol (802.1w)"},{"url":"https://www.cisco.com/c/en/us/td/docs/switches/lan/catalyst9300/software/release/17-9/configuration_guide/sec/b_179_sec_9300_cg/configuring_spanning_tree_protocol.html","label":"Cisco IOS - Spanning Tree Protocol Configuration"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A network engineer is deploying Rapid PVST+ on a Cisco campus network. Which port states are valid under Rapid PVST+ (802.1w)?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A switch access port connects to an end-user PC. The administrator wants the port to immediately start forwarding upon link-up without waiting for the Spanning Tree listening and learning states. Which STP feature should be enabled on this port?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"BPDU Guard"},{"id":"b","text":"Root Guard"},{"id":"c","text":"PortFast"},{"id":"d","text":"Loop Guard"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material states: 'PortFast (skips listening/learning) on access ports.' PortFast is specifically designed to allow access ports connected to end devices (not switches) to bypass the STP listening and learning states and go directly to forwarding, eliminating the typical 30-second delay. BPDU Guard (option A) is a complementary feature that shuts down a PortFast-enabled port if a BPDU is received, but it does not by itself speed up convergence. Root Guard (option B) prevents a port from becoming a root port if a superior BPDU is received. Loop Guard (option D) prevents a non-designated port from becoming a designated port if BPDUs stop being received.$patch$, $patch$Network Access$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/support/docs/lan-switching/spanning-tree-protocol/10588-74.html","label":"Cisco - PortFast, BPDU Guard, and BPDU Filter"},{"url":"https://www.cisco.com/c/en/us/td/docs/switches/lan/catalyst9300/software/release/17-9/configuration_guide/sec/b_179_sec_9300_cg/configuring_optional_spanning_tree_features.html","label":"Cisco Catalyst - STP Enhancements Configuration"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A switch access port connects to an end-user PC. The administrator wants the port to immediately start forwarding upon link-up without waiting for the Spanning Tree listening and learning states. Which STP feature should be enabled on this port?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A network engineer is configuring an EtherChannel between two Cisco switches using an open standard protocol that supports active and passive negotiation modes. Which protocol should be used?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"PAgP (Port Aggregation Protocol)"},{"id":"b","text":"LACP (Link Aggregation Control Protocol)"},{"id":"c","text":"DTP (Dynamic Trunking Protocol)"},{"id":"d","text":"VTP (VLAN Trunking Protocol)"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material states: 'LACP (open standard, 802.3ad), PAgP (Cisco proprietary). Modes: LACP active/passive, PAgP desirable/auto.' LACP is defined by IEEE 802.3ad and is an open standard, making it usable between multi-vendor devices. Its negotiation modes are 'active' (initiates negotiation) and 'passive' (responds to negotiation). PAgP (option A) is Cisco proprietary and uses desirable/auto modes, not active/passive. DTP (option C) is used for trunk negotiation between switch ports, not link aggregation. VTP (option D) propagates VLAN database information across the network.$patch$, $patch$Network Access$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/switches/lan/catalyst9300/software/release/17-9/configuration_guide/bndl/b_179_bndl_9300_cg/configuring_etherchannel.html","label":"Cisco - EtherChannel Configuration Guide"},{"url":"https://www.ieee802.org/3/ad/","label":"IEEE 802.3ad - Link Aggregation"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A network engineer is configuring an EtherChannel between two Cisco switches using an open standard protocol that supports active and passive negotiation modes. Which protocol should be used?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A wireless engineer is designing a 2.4 GHz Wi-Fi network for an office floor and wants to deploy multiple access points without causing co-channel interference between adjacent APs. Which set of channels should be used to ensure non-overlapping coverage in the United States?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Channels 1, 5, 10"},{"id":"b","text":"Channels 1, 6, 11"},{"id":"c","text":"Channels 2, 7, 12"},{"id":"d","text":"Channels 1, 4, 8, 11"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material explicitly states: 'non-overlapping 1, 6, 11 in 2.4 GHz US.' In the 2.4 GHz band in the United States, each channel is 22 MHz wide with 5 MHz spacing between channel center frequencies. Channels 1, 6, and 11 are spaced far enough apart (25 MHz between centers) to avoid overlapping with each other, making them the only three truly non-overlapping channels. Options A, C, and D include channels that overlap with each other spectrally, causing co-channel or adjacent-channel interference.$patch$, $patch$Network Access$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/support/docs/wireless-mobility/wireless-lan-wlan/194099-Best-Practices-for-Selecting-2-4-GHz-Wi.html","label":"Cisco - Wireless LAN Channel Deployment Guide"},{"url":"https://www.cisco.com/c/en/us/products/collateral/wireless/aironet-1700-series/guide-c07-734031.html","label":"Cisco Aironet - RF Design Guide"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A wireless engineer is designing a 2.4 GHz Wi-Fi network for an office floor and wants to deploy multiple access points without causing co-channel interference between adjacent APs. Which set of channels should be used to ensure non-overlapping coverage in the United States?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A company is deploying lightweight access points managed centrally. Which protocol do lightweight APs use to communicate with the Wireless LAN Controller (WLC) for both control and data traffic?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"LWAPP (Lightweight Access Point Protocol)"},{"id":"b","text":"CAPWAP (Control and Provisioning of Wireless Access Points)"},{"id":"c","text":"CDP (Cisco Discovery Protocol)"},{"id":"d","text":"LLDP-MED (Link Layer Discovery Protocol - Media Endpoint Discovery)"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material states: 'Lightweight APs use CAPWAP tunnel to WLC (control + data).' CAPWAP is the current standard protocol (RFC 5415) used by lightweight access points to establish a tunnel to a Wireless LAN Controller, carrying both control plane messages (management) and data plane traffic (client data encapsulated in the tunnel). LWAPP (option A) was CAPWAP's predecessor and is no longer used in modern Cisco deployments. CDP (option C) is a Cisco Layer 2 discovery protocol used to detect neighboring Cisco devices—including APs and phones—but it does not tunnel wireless data. LLDP-MED (option D) is used for voice VLAN discovery by IP phones.$patch$, $patch$Network Access$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/support/docs/wireless-mobility/wireless-lan-wlan/70333-cwap-ap-join.html","label":"Cisco - CAPWAP Access Point Controller Discovery and Join Process"},{"url":"https://www.rfc-editor.org/rfc/rfc5415","label":"RFC 5415 - CAPWAP Protocol Specification"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A company is deploying lightweight access points managed centrally. Which protocol do lightweight APs use to communicate with the Wireless LAN Controller (WLC) for both control and data traffic?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Cisco switch administrator is concerned about the security risk of using the default native VLAN on trunk links. According to best practices, what is the primary security risk associated with leaving the native VLAN as VLAN 1 on a trunk port?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"VLAN 1 traffic is always encrypted, causing performance overhead."},{"id":"b","text":"Untagged frames on the trunk are assigned to VLAN 1, potentially allowing an attacker to send untagged frames to gain access to the native VLAN without a tag."},{"id":"c","text":"VLAN 1 cannot be used with VTP, causing VTP synchronization failures."},{"id":"d","text":"Devices on VLAN 1 are automatically granted trunk negotiation rights via DTP."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material notes: 'native VLAN typically 1 (avoid for security).' The native VLAN on an 802.1Q trunk carries untagged traffic. If an attacker on an access port sends untagged frames (or crafts double-tagged frames in a VLAN hopping attack), those frames can traverse the trunk on the native VLAN without being explicitly tagged, potentially reaching any switch that shares the same native VLAN. Best practice is to change the native VLAN to an unused VLAN ID to mitigate this risk. VLAN 1 traffic is not encrypted (option A). VTP can operate on VLAN 1 (option C). DTP negotiation rights are controlled by port configuration, not VLAN membership (option D).$patch$, $patch$Network Access$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/support/docs/lan-switching/8021q/17056-741-4.html","label":"Cisco - VLAN Security Best Practices"},{"url":"https://www.cisco.com/c/en/us/td/docs/switches/lan/catalyst9300/software/release/17-9/configuration_guide/sec/b_179_sec_9300_cg/preventing_misuse_of_a_cisco_catalyst_switches.html","label":"Cisco - Catalyst Switch Security Configuration Guide"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Cisco switch administrator is concerned about the security risk of using the default native VLAN on trunk links. According to best practices, what is the primary security risk associated with leaving the native VLAN as VLAN 1 on a trunk port?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A network administrator needs to forward DHCP client broadcasts from a remote subnet (192.168.10.0/24) to a centralized DHCP server at 10.1.1.10. Which IOS command must be applied to the router interface that faces the remote client subnet?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"ip dhcp-server 10.1.1.10"},{"id":"b","text":"ip helper-address 10.1.1.10"},{"id":"c","text":"ip dhcp relay 10.1.1.10"},{"id":"d","text":"ip forward-protocol udp 67 10.1.1.10"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material states: 'ip helper-address for relaying DHCP across subnets.' The command 'ip helper-address <server-ip>' is configured on the router interface closest to the DHCP clients; it converts the client's broadcast Discover message into a unicast packet forwarded to the DHCP server. Option A is not a valid IOS command. Option C ('ip dhcp relay') is not the correct IOS syntax. Option D references 'ip forward-protocol udp 67', which is a supporting protocol forwarding command but is not the primary command used to specify the relay destination — 'ip helper-address' is the correct and required command.$patch$, $patch$IP Services$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/ipaddr_dhcp/configuration/xe-16/dhcp-xe-16-book/config-dhcp-server.html#GUID-7B3E7E8E-7A4A-4D4D-9E4A-4E4E4E4E4E4E","label":"Cisco – Configuring DHCP (ip helper-address)"},{"url":"https://developer.cisco.com/docs/ios-xe/#!dhcp/configuring-dhcp","label":"Cisco CCNA 200-301 Official Cert Guide – DHCP Relay"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A network administrator needs to forward DHCP client broadcasts from a remote subnet (192.168.10.0/24) to a centralized DHCP server at 10.1.1.10. Which IOS command must be applied to the router interface that faces the remote client subnet?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$During DHCP lease negotiation, in which order does a client complete the DORA process? Select the sequence that correctly represents all four steps.$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Discover → Offer → Request → Acknowledge"},{"id":"b","text":"Discover → Request → Offer → Acknowledge"},{"id":"c","text":"Offer → Discover → Request → Acknowledge"},{"id":"d","text":"Request → Discover → Offer → Acknowledge"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$The source material explicitly names the client process as 'DORA (Discover, Offer, Request, Ack).' The client first broadcasts a DHCPDISCOVER, the server responds with a DHCPOFFER, the client broadcasts a DHCPREQUEST to accept the offer (and inform other servers), and finally the server confirms with a DHCPACK. Options B, C, and D all place the steps out of order, which would not result in a successful lease negotiation.$patch$, $patch$IP Services$patch$,
         3, $json$[{"url":"https://datatracker.ietf.org/doc/html/rfc2131#section-3.1","label":"RFC 2131 – Dynamic Host Configuration Protocol (DORA process)"},{"url":"https://www.cisco.com/c/en/us/support/docs/ip/dynamic-address-allocation-resolution/27470-100.html","label":"Cisco – Understanding DHCP Lease Process"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$During DHCP lease negotiation, in which order does a client complete the DORA process? Select the sequence that correctly represents all four steps.$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A network engineer is designing a QoS policy for VoIP traffic traversing a WAN link. The policy must guarantee low latency and minimum jitter for voice packets. Which queueing mechanism and DSCP value combination is MOST appropriate?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"CBWFQ with DSCP AF41 (34)"},{"id":"b","text":"LLQ with DSCP EF (46)"},{"id":"c","text":"FIFO with DSCP CS3 (24)"},{"id":"d","text":"WFQ with DSCP BE (0)"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material states: 'Per-Hop Behavior (PHB): EF (Expedited Forwarding, DSCP 46) for voice' and 'Queueing: LLQ (Low Latency Queueing) for voice.' LLQ provides a strict-priority queue that services voice packets before all other traffic, directly addressing the requirement for low latency and minimum jitter. DSCP EF (46) is the industry-standard marking for voice bearer traffic. Option A uses CBWFQ with AF41, which is suited for video conferencing, not voice. Option C uses FIFO, which provides no differentiated treatment. Option D uses WFQ with Best Effort DSCP 0, offering no quality guarantees.$patch$, $patch$IP Services$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/qos_classn/configuration/xe-16/qos-classn-xe-16-book/qos-classn-llq.html","label":"Cisco – QoS: Low Latency Queueing (LLQ) Overview"},{"url":"https://datatracker.ietf.org/doc/html/rfc3246","label":"RFC 3246 – An Expedited Forwarding PHB (DSCP EF = 46)"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A network engineer is designing a QoS policy for VoIP traffic traversing a WAN link. The policy must guarantee low latency and minimum jitter for voice packets. Which queueing mechanism and DSCP value combination is MOST appropriate?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An administrator configures SNMP on a Cisco router and requires that notifications sent to the NMS are acknowledged by the NMS to ensure delivery. Which SNMP message type satisfies this requirement?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"get-bulk"},{"id":"b","text":"trap"},{"id":"c","text":"inform"},{"id":"d","text":"set"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material clearly distinguishes: 'trap (notification)' versus 'inform (acked notification).' An SNMP Inform is identical in purpose to a Trap but adds a reliability mechanism: the NMS sends an acknowledgment (SNMPv2c GetResponse PDU) back to the sender. If no acknowledgment is received within the timeout, the inform is retransmitted. Traps (Option B) are fire-and-forget with no acknowledgment. get-bulk (Option A) is a polling operation to retrieve large tables. set (Option D) is used to modify managed object values on a device.$patch$, $patch$IP Services$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/snmp/configuration/xe-16/snmp-xe-16-book/nm-snmp-cfg-snmp-support.html#GUID-snmp-inform","label":"Cisco – Configuring SNMP Support (Traps vs. Informs)"},{"url":"https://datatracker.ietf.org/doc/html/rfc3416#section-4.2.6","label":"RFC 3416 – Version 2 of the Protocol Operations for SNMP (Inform)"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An administrator configures SNMP on a Cisco router and requires that notifications sent to the NMS are acknowledged by the NMS to ensure delivery. Which SNMP message type satisfies this requirement?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A network engineer reviews syslog messages on a Cisco router and sees messages marked with severity level 3. According to the syslog severity scale, what category do these messages represent?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Debugging – detailed informational messages used for troubleshooting"},{"id":"b","text":"Notification – normal but significant events"},{"id":"c","text":"Error – error conditions that do not immediately impair functionality"},{"id":"d","text":"Critical – critical conditions requiring immediate attention"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material specifies: 'Severity 0 (emergency) to 7 (debug).' The standard syslog severity levels are: 0=Emergency, 1=Alert, 2=Critical, 3=Error, 4=Warning, 5=Notice/Notification, 6=Informational, 7=Debug. Severity 3 maps to 'Error' — conditions that indicate error conditions but do not necessarily cause immediate system failure. Option A describes severity 7 (Debug). Option B describes severity 5 (Notice). Option D describes severity 2 (Critical), which is one level above Error.$patch$, $patch$IP Services$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/routers/access/wireless/software/guide/SysMsgLogging.html","label":"Cisco – System Message Logging (Syslog Severity Levels)"},{"url":"https://datatracker.ietf.org/doc/html/rfc5424#section-6.2.1","label":"RFC 5424 – The Syslog Protocol (Severity Levels Table)"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A network engineer reviews syslog messages on a Cisco router and sees messages marked with severity level 3. According to the syslog severity scale, what category do these messages represent?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A network administrator applies an extended ACL to a router interface to block traffic from a specific source to a specific destination. According to Cisco best practices, where should an extended ACL be applied relative to the traffic source?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"As close to the destination as possible"},{"id":"b","text":"As close to the source as possible"},{"id":"c","text":"On the loopback interface of the router"},{"id":"d","text":"Only on inbound interfaces facing the Internet"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Extended ACLs should be applied as close to the traffic source as possible. Because extended ACLs can match source IP, destination IP, protocol, and ports, placing them near the source prevents unwanted traffic from traversing the network unnecessarily. In contrast, standard ACLs (which match only source IP) are applied closest to the destination to avoid inadvertently blocking traffic to other destinations. The source material states: 'Extended ACLs (100-199 or 2000-2699): match src/dst IP, protocol, ports; apply closest to source.'$patch$, $patch$Security Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/support/docs/security/ios-firewall/23602-confaccesslists.html","label":"Cisco – Access Control Lists (ACL) Overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A network administrator applies an extended ACL to a router interface to block traffic from a specific source to a specific destination. According to Cisco best practices, where should an extended ACL be applied relative to the traffic source?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A switch port is configured with port security in shutdown violation mode. An unauthorized device connects and triggers a violation. Which two outcomes will occur as a result?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The port is placed into an err-disabled state and a syslog/SNMP notification is generated."},{"id":"b","text":"The port silently discards frames from the unauthorized MAC and increments a violation counter with no notification."},{"id":"c","text":"The port discards frames from the unauthorized MAC and generates a syslog notification, but remains up."},{"id":"d","text":"The port allows all traffic but logs the offending MAC address to the DHCP snooping binding table."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$In 'shutdown' violation mode — the default — the switch places the port into an err-disabled state, effectively shutting it down, and sends a syslog and SNMP trap notification. Option B describes 'protect' mode (drops frames, no notification). Option C describes 'restrict' mode (drops frames, increments counter, sends notification but port stays up). Option D is incorrect; port security does not interact with the DHCP snooping binding table in that manner. The source material notes: 'shutdown/restrict/protect violation modes' under port security.$patch$, $patch$Security Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/switches/lan/catalyst2960/software/release/12-2_55_se/configuration/guide/scg2960/swtrafc.html","label":"Cisco – Configuring Port Security"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A switch port is configured with port security in shutdown violation mode. An unauthorized device connects and triggers a violation. Which two outcomes will occur as a result?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$DHCP snooping is enabled on a Cisco switch. Which type of traffic does DHCP snooping drop on an untrusted port?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"DHCP Discover messages originating from client workstations"},{"id":"b","text":"DHCP Offer and DHCP Acknowledgment messages arriving from any device"},{"id":"c","text":"All DHCP traffic, including Discover and Request messages"},{"id":"d","text":"Only DHCP Release messages sent by clients"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$DHCP snooping distinguishes trusted ports (uplinks connected to legitimate DHCP servers) from untrusted ports (client-facing). On untrusted ports, the switch drops DHCP server-originated messages — specifically DHCP Offer and DHCP Acknowledgment (DHCPACK) — because only a trusted port should receive server responses. Client messages such as Discover and Request are permitted on untrusted ports. The source material states: 'Drops bogus DHCP server responses (offer/ack) on untrusted.'$patch$, $patch$Security Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/switches/lan/catalyst6500/ios/12-2SX/configuration/guide/book/snoodhcp.html","label":"Cisco – DHCP Snooping and ARP Inspection"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$DHCP snooping is enabled on a Cisco switch. Which type of traffic does DHCP snooping drop on an untrusted port?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A security engineer needs to choose between RADIUS and TACACS+ for implementing AAA on a Cisco network. The primary requirement is granular per-command authorization for privileged network administrators. Which protocol best meets this requirement, and why?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"RADIUS, because it uses TCP port 49 and encrypts the entire payload, ensuring secure command authorization."},{"id":"b","text":"TACACS+, because it uses TCP, encrypts the entire payload, and natively supports per-command authorization."},{"id":"c","text":"RADIUS, because it uses UDP ports 1812/1813 and provides faster responses for command authorization."},{"id":"d","text":"TACACS+, because it uses UDP and encrypts only the password field, which is sufficient for command authorization."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$TACACS+ (TCP port 49) separates authentication, authorization, and accounting into distinct functions and encrypts the entire payload, making it the preferred choice for per-command authorization. RADIUS (UDP ports 1812/1813) encrypts only the password field and does not natively support granular command-level authorization. Options A and D contain incorrect protocol/port details. The source material states: 'TACACS+ (port 49, TCP, encrypts entire payload, supports command authorization).'$patch$, $patch$Security Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/support/docs/security-vpn/remote-authentication-dial-user-service-radius/13838-10.html","label":"Cisco – Comparing TACACS+ and RADIUS"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A security engineer needs to choose between RADIUS and TACACS+ for implementing AAA on a Cisco network. The primary requirement is granular per-command authorization for privileged network administrators. Which protocol best meets this requirement, and why?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In an 802.1X deployment, which device acts as the authenticator, passing EAP messages between the supplicant and the authentication server?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The end-user workstation (supplicant)"},{"id":"b","text":"The Cisco Identity Services Engine (ISE) server"},{"id":"c","text":"The network access switch or wireless access point"},{"id":"d","text":"The DHCP server that assigns IP addresses after authentication"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$In the 802.1X framework there are three roles: the supplicant (the end-user host requesting access), the authenticator (the switch or access point that enforces access control and relays EAP messages), and the authentication server (such as Cisco ISE or any RADIUS server that validates credentials). The switch/AP does not evaluate credentials itself; it proxies EAP frames to the authentication server. The source material defines: 'Supplicant (host) <-> Authenticator (switch/AP) <-> Authentication Server (ISE/RADIUS).'$patch$, $patch$Security Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/sec_usr_8021x/configuration/xe-16/sec-usr-8021x-xe-16-book/config-ieee-802x-pba.html","label":"Cisco – 802.1X Port-Based Authentication"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$In an 802.1X deployment, which device acts as the authenticator, passing EAP messages between the supplicant and the authentication server?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An administrator enters the command 'service password-encryption' on a Cisco router. What is the security limitation of this configuration?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"It applies only to the enable secret password and has no effect on line passwords."},{"id":"b","text":"It uses a weak, reversible Type 7 cipher that can be easily decoded with publicly available tools."},{"id":"c","text":"It uses MD5 hashing (Type 5), which is vulnerable to rainbow-table attacks."},{"id":"d","text":"It encrypts passwords with AES-256 but requires a master key to be configured first."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$'service password-encryption' protects passwords displayed in the running configuration using Cisco's proprietary Type 7 encoding, which is a simple, reversible XOR-based cipher. Numerous free online tools and scripts can decode Type 7 hashes in seconds, so it provides only minimal protection against casual shoulder-surfing of the config file — not against determined attackers. For stronger protection, 'enable secret' should be used, which employs MD5 (Type 5) or scrypt (Type 9). The source material states: ''service password-encryption' (weak Type 7 reversible cipher).'$patch$, $patch$Security Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/support/docs/security-vpn/ipsec-negotiation-ike-protocols/46420-pre-sh-keys-cln.html","label":"Cisco – Password Encryption Facts"},{"url":"https://www.cisco.com/c/en/us/support/docs/security/ios-firewall/112035-password-protect-routerconf-00.html","label":"Cisco – Protecting Passwords on Cisco Routers"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An administrator enters the command 'service password-encryption' on a Cisco router. What is the security limitation of this configuration?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A network engineer is configuring a site-to-site IPsec VPN between two branch routers. The requirement is that the original IP headers of packets must be fully protected and hidden from intermediary devices. Which IPsec mode satisfies this requirement?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Transport mode, because it encrypts the entire original IP packet including the header."},{"id":"b","text":"Tunnel mode, because it encapsulates the entire original IP packet (including its header) inside a new IP header."},{"id":"c","text":"Transport mode, because it is designed for gateway-to-gateway communication and hides original IP addresses."},{"id":"d","text":"Tunnel mode, because it encrypts only the payload while leaving the original IP header exposed for routing."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$IPsec tunnel mode encapsulates the entire original IP packet — header and payload — inside a new outer IP packet. This hides the original source and destination IP addresses from intermediate devices, making it ideal for site-to-site VPNs between gateways. Transport mode, by contrast, encrypts only the payload and leaves the original IP header intact and visible. The source material states: 'transport (host-host, original IP exposed) vs tunnel (gateway-gateway, original IP encrypted).'$patch$, $patch$Security Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/support/docs/security-vpn/ipsec-negotiation-ike-protocols/115936-understanding-ipsec-modes.html","label":"Cisco – IPsec Modes: Tunnel and Transport"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A network engineer is configuring a site-to-site IPsec VPN between two branch routers. The requirement is that the original IP headers of packets must be fully protected and hidden from intermediary devices. Which IPsec mode satisfies this requirement?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A wireless network administrator is upgrading the corporate Wi-Fi from WPA2-Personal to the latest security standard. Which feature is introduced by WPA3-Personal that directly replaces the Pre-Shared Key (PSK) handshake?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"TKIP (Temporal Key Integrity Protocol) for per-frame key mixing"},{"id":"b","text":"SAE (Simultaneous Authentication of Equals), which provides forward secrecy and resistance to offline dictionary attacks"},{"id":"c","text":"EAP-TLS with mutual certificate-based authentication for every personal device"},{"id":"d","text":"CCMP with AES-128 encryption, which was already available in WPA2-Enterprise"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$WPA3-Personal replaces the WPA2 PSK four-way handshake with SAE (Simultaneous Authentication of Equals), a password-based authentication mechanism derived from the Dragonfly key exchange. SAE provides forward secrecy and is resistant to offline dictionary attacks, meaning an attacker who captures the handshake cannot later crack the password by brute force. TKIP is associated with the older, deprecated WPA standard. EAP-TLS is an 802.1X/Enterprise mechanism. CCMP/AES was already part of WPA2. The source material states: 'WPA3 (SAE - Simultaneous Authentication of Equals, replaces PSK).'$patch$, $patch$Security Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/products/collateral/wireless/nb-06-wpa3-dep-guide-cte-en.html","label":"Cisco – WPA3 Deployment Guide"},{"url":"https://www.wi-fi.org/discover-wi-fi/security","label":"Wi-Fi Alliance – WPA3 Security"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A wireless network administrator is upgrading the corporate Wi-Fi from WPA2-Personal to the latest security standard. Which feature is introduced by WPA3-Personal that directly replaces the Pre-Shared Key (PSK) handshake?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Dynamic ARP Inspection (DAI) is enabled on a Cisco switch. Which underlying security feature must also be configured for DAI to validate ARP packets on untrusted ports?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Port security with sticky MAC learning enabled on all access ports"},{"id":"b","text":"802.1X authentication with ISE as the authentication server"},{"id":"c","text":"DHCP snooping, whose binding table provides the IP-to-MAC mappings used by DAI"},{"id":"d","text":"IP Source Guard with an explicit permit ACL for each valid host IP address"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$DAI validates ARP packets by comparing the sender IP and sender MAC address in each ARP message against the DHCP snooping binding table. If the IP-to-MAC mapping in the ARP packet does not match an entry in that table, the packet is dropped, preventing ARP poisoning attacks. Without DHCP snooping (or statically configured ARP ACLs for hosts using static IPs), DAI has no reference table to perform its validation. The source material states: 'DAI — Validate ARP packets against DHCP snooping binding table' and 'DHCP snooping — Builds binding table for DAI and IP Source Guard.'$patch$, $patch$Security Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/switches/lan/catalyst6500/ios/12-2SX/configuration/guide/book/dynarp.html","label":"Cisco – Dynamic ARP Inspection Overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Dynamic ARP Inspection (DAI) is enabled on a Cisco switch. Which underlying security feature must also be configured for DAI to validate ARP packets on untrusted ports?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A network engineer wants to retrieve the current running configuration from a Cisco IOS-XE device using NETCONF. Which TCP port does NETCONF use by default, and which transport protocol does it rely on?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Port 443 over TLS"},{"id":"b","text":"Port 830 over SSH"},{"id":"c","text":"Port 80 over HTTP"},{"id":"d","text":"Port 22 over Telnet"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$According to RFC 6241, NETCONF operates over SSH on TCP port 830. The source material explicitly states: 'NETCONF (RFC 6241): XML over SSH (port 830).' Port 443 is used by RESTCONF (HTTPS), port 80 is plain HTTP (not used by NETCONF), and Telnet runs on port 23, not 22 — moreover, Telnet is not a valid NETCONF transport.$patch$, $patch$Automation and Programmability$patch$,
         3, $json$[{"url":"https://datatracker.ietf.org/doc/html/rfc6241","label":"RFC 6241 – Network Configuration Protocol (NETCONF)"},{"url":"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/prog/configuration/1612/b_1612_programmability_cg/configuring_yang_datamodel.html","label":"Cisco IOS XE NETCONF/YANG Configuration Guide"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
