INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Cisco switch port connected to an end-user workstation is configured with PortFast. What is the primary benefit of enabling PortFast on this access port?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"It allows the port to carry multiple VLANs simultaneously"},{"id":"b","text":"It prevents the port from ever entering a blocking state due to superior BPDUs"},{"id":"c","text":"It causes the port to skip the listening and learning states and transition directly to forwarding"},{"id":"d","text":"It enables BPDU filtering so no BPDUs are sent or received on the port"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material states: 'PortFast (skips listening/learning) on access ports.' PortFast allows an access port to immediately transition to the forwarding state, bypassing the listening (15 seconds) and learning (15 seconds) states, which reduces the time end devices wait before they can pass traffic. Option B describes Root Guard behavior. Option D describes BPDU Filter. Option A describes a trunk port, not PortFast.$patch$, $patch$Network Access$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/switches/lan/catalyst9300/software/release/17-9/configuration_guide/stp/b_179_stp_9300_cg/configuring_optional_spanning_tree_features.html","label":"Cisco – Configuring PortFast, BPDU Guard, and BPDU Filter"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
