INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A wireless network administrator is deploying APs in a 2.4 GHz environment and wants to use only non-overlapping channels in the United States to minimize co-channel interference. Which set of channels should be selected?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Channels 1, 5, and 10"},{"id":"b","text":"Channels 1, 6, and 11"},{"id":"c","text":"Channels 2, 6, and 10"},{"id":"d","text":"Channels 1, 7, and 13"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material states: 'Non-overlapping 1, 6, 11 in 2.4 GHz US.' In the 2.4 GHz band (US), each channel is 22 MHz wide and channels are spaced 5 MHz apart, meaning channels 1, 6, and 11 are the only three that do not overlap with each other. All other combinations (1/5/10, 2/6/10, 1/7/13) include channels that overlap, causing co-channel or adjacent-channel interference. Channels 12, 13, and 14 are also not permitted for general use in the US.$patch$, $patch$Network Access$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/support/docs/wireless-mobility/wireless-lan-wlan/27147-non-overlap-channels.html","label":"Cisco – Wireless LAN Channel Selection and Deployment"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
