INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An automation script calls a Cisco DNA Center REST API endpoint and receives an HTTP 401 response code. What does this status code indicate?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The requested resource was not found on the server."},{"id":"b","text":"The client has not been authenticated and cannot access the resource."},{"id":"c","text":"The server encountered an internal error and could not fulfill the request."},{"id":"d","text":"The request was malformed and the server could not understand it."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Per the source material, HTTP 401 means 'Unauthorized,' indicating the client has not successfully authenticated. A 404 means the resource was Not Found, a 500 indicates a Server Error, and a 400 indicates a Bad Request (malformed syntax). Correct authentication credentials or a valid token must be provided to resolve a 401 error.$patch$, $patch$Automation and Programmability$patch$,
         3, $json$[{"url":"https://developer.cisco.com/docs/dna-center/#!authentication-api","label":"Cisco DNA Center Authentication API"},{"url":"https://developer.mozilla.org/en-US/docs/Web/HTTP/Status/401","label":"MDN Web Docs - HTTP Status Codes"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P5'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An automation script calls a Cisco DNA Center REST API endpoint and receives an HTTP 401 response code. What does this status code indicate?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A network architect is comparing Ansible and Puppet for automating Cisco router configurations. Which statement correctly describes a key difference between these two tools?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Ansible requires a software agent installed on each managed network device, while Puppet is agentless."},{"id":"b","text":"Ansible is agentless and uses YAML playbooks, while Puppet requires an agent installed on managed devices."},{"id":"c","text":"Both Ansible and Puppet are agentless and use YAML for configuration."},{"id":"d","text":"Ansible uses a declarative state file, while Puppet uses imperative YAML playbooks."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material explicitly states that 'Ansible: agentless, YAML playbooks' and 'Puppet/Chef: agent-based.' This means Ansible does not require any software pre-installed on managed devices (it uses SSH), while Puppet requires an agent daemon running on each managed node. Terraform — not Ansible — uses a declarative state file.$patch$, $patch$Automation and Programmability$patch$,
         3, $json$[{"url":"https://developer.cisco.com/network-automation/detail/ansible/","label":"Cisco DevNet - Ansible for Network Automation"},{"url":"https://docs.ansible.com/ansible/latest/network/index.html","label":"Ansible Network Automation Documentation"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P5'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A network architect is comparing Ansible and Puppet for automating Cisco router configurations. Which statement correctly describes a key difference between these two tools?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which data serialization format uses indentation to define structure, is human-readable, and is the native format for writing Ansible playbooks?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"JSON (JavaScript Object Notation)"},{"id":"b","text":"XML (Extensible Markup Language)"},{"id":"c","text":"YAML (YAML Ain't Markup Language)"},{"id":"d","text":"CSV (Comma-Separated Values)"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material states 'YAML: indentation-sensitive, used in Ansible playbooks.' YAML relies on whitespace indentation to define data hierarchy, making it highly human-readable. JSON uses key-value pairs with curly braces and is used in REST APIs, while XML uses opening and closing tags and is used in NETCONF. CSV is a flat tabular format not used for Ansible.$patch$, $patch$Automation and Programmability$patch$,
         3, $json$[{"url":"https://docs.ansible.com/ansible/latest/playbook_guide/playbooks_intro.html","label":"Ansible Playbook Documentation"},{"url":"https://developer.cisco.com/learning/labs/intro-to-coding-for-network-engineers/introduction/","label":"Cisco DevNet - Data Formats for Network Automation"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
