INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An organization wants to ensure that voice traffic across its WAN receives the lowest possible delay and jitter. According to QoS best practices, which DSCP Per-Hop Behavior (PHB) and decimal DSCP value should be applied to the voice bearer (RTP) traffic?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Assured Forwarding (AF41), DSCP 34"},{"id":"b","text":"Expedited Forwarding (EF), DSCP 46"},{"id":"c","text":"Class Selector 7 (CS7), DSCP 56"},{"id":"d","text":"Default Forwarding (DF), DSCP 0"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material explicitly states: 'EF (Expedited Forwarding, DSCP 46) for voice.' EF is the standard PHB for real-time voice bearer streams because routers are expected to empty the EF queue quickly, minimizing latency and jitter. AF41 (DSCP 34) is commonly used for interactive video, not voice bearer. CS7 (DSCP 56) is reserved for network control traffic. DF/DSCP 0 is best-effort with no priority guarantees.$patch$, $patch$IP Services$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/solutions/Enterprise/WAN_and_MAN/QoS_SRND/QoS-SRND-Book/QoSIntro.html","label":"Cisco QoS Design Guide – DSCP and PHB Markings"},{"url":"https://www.rfc-editor.org/rfc/rfc3246","label":"RFC 3246 – An Expedited Forwarding PHB"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An organization wants to ensure that voice traffic across its WAN receives the lowest possible delay and jitter. According to QoS best practices, which DSCP Per-Hop Behavior (PHB) and decimal DSCP value should be applied to the voice bearer (RTP) traffic?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Cisco network device sends an SNMP notification to a management station, and the notification requires an acknowledgment from the manager to confirm receipt. Which SNMP message type is being used?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"get-bulk"},{"id":"b","text":"trap"},{"id":"c","text":"set"},{"id":"d","text":"inform"}]$json$::jsonb, $json$["d"]$json$::jsonb, $patch$The source material states: 'trap (notification), inform (acked notification).' An SNMP inform is identical in purpose to a trap (unsolicited notification from agent to manager) but adds a reliability mechanism: the manager must send an acknowledgment. If no acknowledgment is received within a timeout period, the agent retransmits the inform. A trap is fire-and-forget with no acknowledgment. get-bulk retrieves large amounts of MIB data. set modifies MIB object values.$patch$, $patch$IP Services$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/snmp/configuration/xe-16/snmp-xe-16-book/nm-snmp-cfg-snmp-support.html","label":"Cisco IOS Network Management Configuration Guide – SNMP Informs"},{"url":"https://www.rfc-editor.org/rfc/rfc3416","label":"RFC 3416 – Version 2 of the Protocol Operations for SNMP"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Cisco network device sends an SNMP notification to a management station, and the notification requires an acknowledgment from the manager to confirm receipt. Which SNMP message type is being used?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A network operations team is configuring syslog on a Cisco router. They need to capture messages related to normal but significant operational events, such as interface state changes. According to the syslog severity scale, which severity level BEST represents these events?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Severity 0 – Emergency"},{"id":"b","text":"Severity 3 – Error"},{"id":"c","text":"Severity 5 – Notification"},{"id":"d","text":"Severity 7 – Debug"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material states the syslog scale runs from 'Severity 0 (emergency) to 7 (debug).' Interface up/down events (link state changes) are classified as Severity 5 – Notification (NOTIFICATION), which represents normal but significant operational events that an administrator should be aware of. Severity 0 (Emergency) is reserved for system-unusable conditions. Severity 3 (Error) covers error conditions that do not cause a system-wide failure. Severity 7 (Debug) produces highly verbose output used only during troubleshooting and would be inappropriate for routine operational monitoring.$patch$, $patch$IP Services$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/config_fundamentals/configuration/xe-16/cf-xe-16-book/cf-log-overview.html","label":"Cisco IOS Configuration Fundamentals Configuration Guide – Syslog"},{"url":"https://www.rfc-editor.org/rfc/rfc5424","label":"RFC 5424 – The Syslog Protocol"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A network operations team is configuring syslog on a Cisco router. They need to capture messages related to normal but significant operational events, such as interface state changes. According to the syslog severity scale, which severity level BEST represents these events?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A network administrator needs to filter traffic based on both source IP address and destination TCP port number. Which type of ACL should be used, and where should it be applied?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Standard ACL applied closest to the source"},{"id":"b","text":"Extended ACL applied closest to the source"},{"id":"c","text":"Standard ACL applied closest to the destination"},{"id":"d","text":"Extended ACL applied closest to the destination"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material states that Extended ACLs (numbered 100-199 or 2000-2699) can match source/destination IP, protocol, and ports — making them necessary when filtering on TCP port in addition to source IP. Extended ACLs should be applied closest to the source so that unwanted traffic is blocked early and does not consume bandwidth traversing the network unnecessarily. Standard ACLs only match source IP and are placed closest to the destination, so options A and C are incorrect. Option D places the extended ACL at the wrong location (closest to destination).$patch$, $patch$Security Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/support/docs/security/ios-firewall/23602-confaccesslists.html","label":"Cisco – Access Control Lists (ACL) Overview"},{"url":"https://learningnetwork.cisco.com/s/ccna-exam-topics","label":"Cisco Learning Network – CCNA 200-301 Exam Topics"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A network administrator needs to filter traffic based on both source IP address and destination TCP port number. Which type of ACL should be used, and where should it be applied?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which statement correctly describes the behavior of the implicit deny rule at the end of every Cisco ACL?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"It only applies to inbound traffic and must be manually configured."},{"id":"b","text":"It drops any traffic that does not match any preceding permit or deny statement in the ACL."},{"id":"c","text":"It permits all traffic that does not match a deny statement."},{"id":"d","text":"It is overridden when 'ip access-group' is applied with the 'out' keyword."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material explicitly states there is an 'implicit deny at end' of every ACL and that matching is 'top-down, first match.' This means any packet that does not match any explicit permit or deny entry is silently dropped by this implicit deny-all statement. It does not need to be manually configured (A is wrong), it does not permit unmatched traffic (C is wrong), and the direction keyword 'in/out' used with 'ip access-group' does not change this behavior (D is wrong).$patch$, $patch$Security Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/support/docs/security/ios-firewall/23602-confaccesslists.html","label":"Cisco – Understanding ACLs: Implicit Deny"},{"url":"https://www.ciscopress.com/store/ccna-200-301-official-cert-guide-library-9781587147142","label":"Cisco CCNA 200-301 Official Cert Guide, ACL Chapter"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which statement correctly describes the behavior of the implicit deny rule at the end of every Cisco ACL?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A switch port is configured with port security. After a violation occurs, the interface is still forwarding traffic for existing MAC addresses, but all frames from unknown MAC addresses are silently dropped and no log message is generated. Which violation mode is active on this port?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Shutdown"},{"id":"b","text":"Restrict"},{"id":"c","text":"Protect"},{"id":"d","text":"Dynamic"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material lists three port security violation modes: shutdown, restrict, and protect. In 'protect' mode, frames from unknown MAC addresses are dropped silently without any log or SNMP notification, and the port remains up for already-learned addresses. 'Restrict' mode also drops frames and keeps the port up, but it does generate a log/SNMP notification — so B is incorrect given the scenario description of no log message. 'Shutdown' would err-disable the port entirely (A is wrong). 'Dynamic' is not a port security violation mode (D is wrong).$patch$, $patch$Security Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/switches/lan/catalyst2960/software/release/12-2_55_se/configuration/guide/scg_2960/swtrafc.html","label":"Cisco – Configuring Port Security"},{"url":"https://www.ciscopress.com/store/ccna-200-301-official-cert-guide-library-9781587147142","label":"Cisco CCNA 200-301 Official Cert Guide – Port Security"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A switch port is configured with port security. After a violation occurs, the interface is still forwarding traffic for existing MAC addresses, but all frames from unknown MAC addresses are silently dropped and no log message is generated. Which violation mode is active on this port?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$DHCP snooping is enabled on a Cisco switch. A port connected to the core distribution switch (which relays DHCP to the server) is erroneously left as 'untrusted.' What is the most likely result?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"End hosts will receive IP addresses from a rogue DHCP server."},{"id":"b","text":"DHCP Offer and Acknowledge messages arriving on that port will be dropped, causing clients to fail to obtain IP addresses."},{"id":"c","text":"The switch will add rogue DHCP server entries to the snooping binding table."},{"id":"d","text":"ARP packets will be blocked on that port by Dynamic ARP Inspection."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material states that DHCP snooping 'drops bogus DHCP server responses (offer/ack) on untrusted' ports. If the legitimate uplink to the DHCP relay/server is marked untrusted, the switch will drop all DHCP Offer and Acknowledge packets arriving on that port — preventing clients from getting valid IP addresses. Option A describes the problem DHCP snooping is designed to prevent, not a result of misconfiguring trust. Option C is incorrect because the binding table is populated only by legitimate DHCP exchanges on trusted ports. Option D conflates DAI (which inspects ARP) with DHCP snooping.$patch$, $patch$Security Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/switches/lan/catalyst9300/software/release/17-6/configuration_guide/sec/b_176_sec_9300_cg/configuring_dhcp_snooping.html","label":"Cisco – DHCP Snooping Configuration Guide"},{"url":"https://learningnetwork.cisco.com/s/ccna-exam-topics","label":"Cisco CCNA 200-301 Exam Topics – Security Fundamentals"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$DHCP snooping is enabled on a Cisco switch. A port connected to the core distribution switch (which relays DHCP to the server) is erroneously left as 'untrusted.' What is the most likely result?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which of the following statements best distinguishes TACACS+ from RADIUS in a Cisco AAA deployment?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"TACACS+ uses UDP port 1812 and encrypts only the password field in its packets."},{"id":"b","text":"RADIUS uses TCP port 49 and supports per-command authorization natively."},{"id":"c","text":"TACACS+ uses TCP port 49, encrypts the entire payload, and supports command authorization."},{"id":"d","text":"RADIUS encrypts the entire payload and uses TCP for reliable delivery."}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material clearly states: TACACS+ uses 'port 49, TCP, encrypts entire payload, supports command authorization,' while RADIUS uses 'port 1812/1813, UDP, encrypts password only.' Option A incorrectly attributes UDP/1812 to TACACS+. Option B incorrectly attributes TCP/49 and command authorization to RADIUS. Option D is doubly wrong — RADIUS uses UDP and encrypts only the password. Only option C accurately reflects the TACACS+ characteristics from the source.$patch$, $patch$Security Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/support/docs/security-vpn/remote-authentication-dial-user-service-radius/13838-10.html","label":"Cisco – Comparing TACACS+ and RADIUS"},{"url":"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/sec_usr_aaa/configuration/xe-16/sec-usr-aaa-xe-16-book/sec-cfg-authentication.html","label":"Cisco AAA Configuration Guide"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which of the following statements best distinguishes TACACS+ from RADIUS in a Cisco AAA deployment?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In an 802.1X deployment on a Cisco campus network, which device acts as the authenticator?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The end-user laptop running the 802.1X supplicant software"},{"id":"b","text":"The Cisco Identity Services Engine (ISE) server"},{"id":"c","text":"The access-layer switch or wireless access point to which the client connects"},{"id":"d","text":"The RADIUS proxy server sitting between the switch and ISE"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material defines the three 802.1X roles as: 'Supplicant (host) <-> Authenticator (switch/AP) <-> Authentication Server (ISE/RADIUS).' The access-layer switch or wireless access point plays the authenticator role — it enforces port access by relaying EAP messages between the supplicant and the authentication server. The end-user device is the supplicant (A is wrong). ISE/RADIUS is the authentication server (B is wrong). A RADIUS proxy is not one of the three defined roles in the source (D is wrong).$patch$, $patch$Security Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/sec_usr_8021x/configuration/xe-16/sec-usr-8021x-xe-16-book/config-ieee-802x-pba.html","label":"Cisco – IEEE 802.1X Port-Based Authentication"},{"url":"https://www.cisco.com/c/en/us/products/security/identity-services-engine/index.html","label":"Cisco Identity Services Engine (ISE) Overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$In an 802.1X deployment on a Cisco campus network, which device acts as the authenticator?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A junior engineer types 'service password-encryption' on a Cisco router and believes all passwords are now securely protected. Which statement most accurately evaluates this belief?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The belief is correct; service password-encryption applies AES-256 encryption to all passwords."},{"id":"b","text":"The belief is incorrect; service password-encryption applies only a weak, reversible Type 7 cipher and should be supplemented with 'enable secret' for privileged access."},{"id":"c","text":"The belief is partially correct; service password-encryption uses MD5 hashing for line passwords but Type 7 for the enable password."},{"id":"d","text":"The belief is correct because Type 7 encryption cannot be decoded without the router's private key."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material explicitly states that 'service password-encryption' produces 'weak Type 7 reversible cipher,' meaning the obfuscation can be easily reversed with freely available tools. The source contrasts this with 'enable secret,' which uses MD5 (Type 5, salted) or scrypt (Type 9), both far stronger. Option A incorrectly claims AES-256. Option C inverts the actual behavior. Option D is false — Type 7 is reversible without any private key.$patch$, $patch$Security Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/security/authentication/configuration/xe-16/sec-usr-auth-xe-16-book/sec-encrypt-passwords.html","label":"Cisco – Passwords and Privileges"},{"url":"https://www.ciscopress.com/store/ccna-200-301-official-cert-guide-library-9781587147142","label":"Cisco CCNA 200-301 Official Cert Guide – Password Security"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A junior engineer types 'service password-encryption' on a Cisco router and believes all passwords are now securely protected. Which statement most accurately evaluates this belief?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A company is deploying a site-to-site VPN between two branch offices. The security architect specifies that the original IP headers of all packets must be fully encrypted and hidden from the public internet, and that the VPN endpoints are routers at each site rather than the end hosts themselves. Which IPsec mode satisfies both requirements?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Transport mode with ESP"},{"id":"b","text":"Tunnel mode with AH"},{"id":"c","text":"Tunnel mode with ESP"},{"id":"d","text":"Transport mode with AH"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material distinguishes two IPsec modes: 'transport (host-host, original IP exposed)' and 'tunnel (gateway-gateway, original IP encrypted).' Since the VPN is between routers (gateways) and the original IP headers must be hidden, tunnel mode is required. ESP (Encapsulating Security Payload) provides encryption, while AH (Authentication Header) provides integrity but no encryption. Therefore tunnel mode with ESP is the only option that satisfies both requirements. Transport mode exposes original IP headers (A and D wrong). AH does not encrypt data or headers (B and D wrong).$patch$, $patch$Security Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/support/docs/security-vpn/ipsec-negotiation-ike-protocols/14106-how-ipsec-protocols-work.html","label":"Cisco – IPsec Overview: Transport and Tunnel Modes"},{"url":"https://www.cisco.com/c/en/us/td/docs/routers/access/800/software/guides/800_IPSEC_IKE_Config_Guide.html","label":"Cisco – Site-to-Site VPN Configuration Guide"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A company is deploying a site-to-site VPN between two branch offices. The security architect specifies that the original IP headers of all packets must be fully encrypted and hidden from the public internet, and that the VPN endpoints are routers at each site rather than the end hosts themselves. Which IPsec mode satisfies both requirements?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A wireless network administrator is upgrading the corporate WLAN from WPA2-Personal to a newer standard. The primary goal is to replace the Pre-Shared Key handshake with a method that provides forward secrecy and resistance to offline dictionary attacks. Which security standard and authentication mechanism should be selected?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"WPA with TKIP"},{"id":"b","text":"WPA2-Enterprise with 802.1X"},{"id":"c","text":"WPA3 with Simultaneous Authentication of Equals (SAE)"},{"id":"d","text":"WEP with a 256-bit key"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material states that 'WPA3 (SAE - Simultaneous Authentication of Equals, replaces PSK)' is the modern standard. SAE is specifically designed to replace the WPA2-Personal PSK four-way handshake, providing resistance to offline dictionary attacks and supporting forward secrecy. WPA with TKIP (A) is described as 'obsolete/insecure.' WPA2-Enterprise with 802.1X (B) uses a RADIUS/AAA infrastructure and certificates/EAP rather than replacing PSK with SAE — it solves a different problem. WEP (D) is explicitly listed as 'obsolete/insecure' in the source.$patch$, $patch$Security Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/products/collateral/wireless/nb-06-wpa3-wp-cte-en.html","label":"Cisco – WPA3 Overview and Configuration"},{"url":"https://www.wi-fi.org/discover-wi-fi/security","label":"Wi-Fi Alliance – WPA3 Specification"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A wireless network administrator is upgrading the corporate WLAN from WPA2-Personal to a newer standard. The primary goal is to replace the Pre-Shared Key handshake with a method that provides forward secrecy and resistance to offline dictionary attacks. Which security standard and authentication mechanism should be selected?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A network engineer wants to retrieve the current running configuration from a Cisco IOS-XE device using NETCONF. Which TCP port and transport protocol does NETCONF use by default?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"TCP port 443 over HTTPS"},{"id":"b","text":"TCP port 830 over SSH"},{"id":"c","text":"TCP port 161 over UDP"},{"id":"d","text":"TCP port 80 over HTTP"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material explicitly states: 'NETCONF (RFC 6241): XML over SSH (port 830).' NETCONF uses SSH as its transport, operating on TCP port 830. Port 443 is used by HTTPS (RESTCONF uses HTTPS but is a separate protocol). Port 161/UDP is SNMP. Port 80 is plain HTTP, which NETCONF does not use.$patch$, $patch$Automation and Programmability$patch$,
         3, $json$[{"url":"https://www.rfc-editor.org/rfc/rfc6241","label":"RFC 6241 – Network Configuration Protocol (NETCONF)"},{"url":"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/prog/configuration/173/b_173_programmability_cg/netconf_protocol.html","label":"Cisco IOS XE Programmability Configuration Guide – NETCONF Protocol"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A network engineer wants to retrieve the current running configuration from a Cisco IOS-XE device using NETCONF. Which TCP port and transport protocol does NETCONF use by default?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An automation engineer is writing an Ansible playbook to push interface configurations to a fleet of Cisco routers. Which data format does Ansible use natively for its playbooks?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"JSON"},{"id":"b","text":"XML"},{"id":"c","text":"YAML"},{"id":"d","text":"CSV"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material states: 'Ansible: agentless, YAML playbooks, modules (ios_config, ios_facts).' Ansible playbooks are written in YAML, which is indentation-sensitive. JSON is used primarily with REST APIs. XML is used by NETCONF. CSV is a data-exchange format not used for playbooks.$patch$, $patch$Automation and Programmability$patch$,
         3, $json$[{"url":"https://docs.ansible.com/ansible/latest/playbook_guide/playbooks_intro.html","label":"Ansible Documentation – Working with Playbooks"},{"url":"https://www.ciscopress.com/store/ccna-200-301-official-cert-guide-library-9781587147142","label":"Cisco CCNA 200-301 Official Cert Guide – Automation Chapter"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P6'
